#!/usr/bin/env bash
# Submit KNOT re-encoding pipeline to Cloud Build (minimal source tarball).
#
# Usage:
#   ./scripts/submit-knot-reencode-cloud.sh                  # all models
#   ./scripts/submit-knot-reencode-cloud.sh smollm2-360m     # single model
#   ./scripts/submit-knot-reencode-cloud.sh smollm2-360m 2   # single model, 2 layers (smoke)
#   ./scripts/submit-knot-reencode-cloud.sh all              # all models (explicit)
#
# Arguments:
#   $1  MODELS    comma-separated model IDs or "all" (default: all)
#   $2  MAX_LAYERS  max layers per model (default: all)
#
# Avoids uploading the full 2.6 GiB monorepo by copying only:
#   - encode-ssm-models.py, encode-knot.py, upload-to-r2.py
#   - cloudbuild-knot-reencode.yaml (from monorepo root)
set -euo pipefail

MODELS="${1:-all}"
MAX_LAYERS="${2:-}"

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
DI_ROOT="$(cd "${SCRIPT_DIR}/.." && pwd)"
MONOREPO_ROOT="$(cd "${DI_ROOT}/../../.." && pwd)"

TMP="$(mktemp -d)"
cleanup() { rm -rf "${TMP}"; }
trap cleanup EXIT

mkdir -p "${TMP}/open-source/gnosis/distributed-inference"
cp "${DI_ROOT}/encode-ssm-models.py"    "${TMP}/open-source/gnosis/distributed-inference/"
cp "${DI_ROOT}/encode-knot.py"          "${TMP}/open-source/gnosis/distributed-inference/"
cp "${DI_ROOT}/upload-to-r2.py"         "${TMP}/open-source/gnosis/distributed-inference/"

# Cloud Build YAML from monorepo root
cp "${MONOREPO_ROOT}/cloudbuild-knot-reencode.yaml" "${TMP}/"

echo "[submit] tmpdir contents:"
find "${TMP}" -not -type d | sort

# Build substitutions
SUBS="_MODELS=${MODELS}"
if [[ -n "${MAX_LAYERS}" ]]; then
  SUBS="${SUBS},_MAX_LAYERS=${MAX_LAYERS}"
fi

echo "[submit] submitting build (models=${MODELS} max_layers=${MAX_LAYERS:-all})"
gcloud builds submit \
  --config="${TMP}/cloudbuild-knot-reencode.yaml" \
  --substitutions="${SUBS}" \
  "${TMP}"
